using System;
using System.Collections.Generic;

class Program
{
    static void Main(string[] args)
    {
        List<string> fruits = new List<string>();

        fruits.Add("Alma");
        fruits.Add("Armud");
        fruits.Add("Banan");

        Console.WriteLine("Meyvələr:");
        foreach (string fruit in fruits)
        {
            Console.WriteLine(fruit);
        }

        fruits.Remove("Armud");
        Console.WriteLine("\nArmud silindikdən sonra:");
        foreach (string fruit in fruits)
        {
            Console.WriteLine(fruit);
        }

        Console.WriteLine($"\nİlk meyvə: {fruits[0]}");
        Console.WriteLine($"Meyvə sayı: {fruits.Count}");
    }
}
// Output:
// Meyvələr:
// Alma
// Armud
// Banan
//
// Armud silindikdən sonra:
// Alma
// Banan
//
// İlk meyvə: Alma
// Meyvə sayı: 2

using System;
using System.Collections.Generic;

class Program
{
    static void Main(string[] args)
    {
        Dictionary<string, int> studentScores = new Dictionary<string, int>();

        studentScores.Add("Ali", 85);
        studentScores.Add("Ayşə", 92);
        studentScores.Add("Veli", 78);

        Console.WriteLine("Tələbə qiymətləri:");
        foreach (var pair in studentScores)
        {
            Console.WriteLine($"{pair.Key}: {pair.Value}");
        }

        if (studentScores.ContainsKey("Ayşə"))
        {
            Console.WriteLine($"\nAyşənin qiyməti: {studentScores["Ayşə"]}");
        }

        studentScores.Remove("Veli");
        Console.WriteLine("\nVeli silindikdən sonra:");
        foreach (var pair in studentScores)
        {
            Console.WriteLine($"{pair.Key}: {pair.Value}");
        }
    }
}
// Output:
// Tələbə qiymətləri:
// Ali: 85
// Ayşə: 92
// Veli: 78
//
// Ayşənin qiyməti: 92
//
// Veli silindikdən sonra:
// Ali: 85
// Ayşə: 92

using System;
using System.Collections.Generic;

class Program
{
    static void Main(string[] args)
    {
        HashSet<int> numbers = new HashSet<int>();

        numbers.Add(1);
        numbers.Add(2);
        numbers.Add(2); // Təkrarlanan element əlavə olunmur
        numbers.Add(3);

        Console.WriteLine("Rəqəmlər:");
        foreach (int number in numbers)
        {
            Console.WriteLine(number);
        }

        if (numbers.Contains(2))
        {
            Console.WriteLine("\n2 rəqəmi mövcuddur.");
        }

        numbers.Remove(1);
        Console.WriteLine("\n1 silindikdən sonra:");
        foreach (int number in numbers)
        {
            Console.WriteLine(number);
        }
    }
}
// Output:
// Rəqəmlər:
// 1
// 2
// 3
//
// 2 rəqəmi mövcuddur.
//
// 1 silindikdən sonra:
// 2
// 3

